function showThis() {
  console.log(this);
}

showThis(); // window (browser, non-strict) or undefined (strict mode)

// Arrow functions in global scope: this is also the global object
const show = () => console.log(this); // window (since arrow inherits outer scope)

const user = {
  name: 'Alice',
  greet() {
    console.log(`Hello, I'm ${this.name}`);
  }
};

user.greet(); // 'Hello, I'm Alice'  — this === user

function greet(greeting) {
  console.log(`${greeting}, I'm ${this.name}`);
}

const user = { name: 'Alice' };

// call: invoke immediately, pass args one by one
greet.call(user, 'Hello');     // 'Hello, I'm Alice'

// apply: invoke immediately, pass args as array
greet.apply(user, ['Hi']);     // 'Hi, I'm Alice'

// bind: returns a NEW function with 'this' permanently set
const boundGreet = greet.bind(user);
boundGreet('Hey');             // 'Hey, I'm Alice'

function Person(name) {
  // When called with 'new', 'this' is a fresh empty object
  this.name = name;
  this.greet = function() {
    console.log(`Hello, I'm ${this.name}`);
  };
}

const alice = new Person('Alice');
alice.greet(); // 'Hello, I'm Alice'

const user = {
  name: 'Alice',
  greet() {
    console.log(`Hello, ${this.name}`);
  }
};

user.greet(); // 'Hello, Alice' — called on the object, this === user

const fn = user.greet; // extract the function
fn();                  // 'Hello, undefined' — called without object context!

// Passes user.greet as a callback — 'this' is lost
setTimeout(user.greet, 1000); // 'Hello, undefined'

// Solutions:
setTimeout(() => user.greet(), 1000);         // arrow wrapper — calls on user
setTimeout(user.greet.bind(user), 1000);      // bind — locks this to user

const timer = {
  count: 0,
  start() {
    // Regular function — 'this' is lost inside the callback:
    setInterval(function() {
      this.count++; // ❌ 'this' is window or undefined, not timer
    }, 1000);

    // Arrow function — inherits 'this' from start(), which is timer:
    setInterval(() => {
      this.count++; // ✅ 'this' is timer
    }, 1000);
  }
};

timer.start();

class Counter extends React.Component {
  constructor(props) {
    super(props);
    this.state = { count: 0 };

    // Option 1: Bind in constructor (common pattern)
    this.handleClick = this.handleClick.bind(this);
  }

  handleClick() {
    // 'this' must be the component instance to access this.setState
    this.setState({ count: this.state.count + 1 });
  }

  render() {
    return (
      <button onClick={this.handleClick}>
        {this.state.count}
      </button>
    );
  }
}

// Option 2: Arrow function class field (avoids bind in constructor)
class Counter extends React.Component {
  state = { count: 0 };

  // Arrow function — 'this' is lexically bound to the class instance
  handleClick = () => {
    this.setState({ count: this.state.count + 1 });
  };

  render() {
    return <button onClick={this.handleClick}>{this.state.count}</button>;
  }
}

// Function component — no 'this' anywhere
function Counter() {
  const [count, setCount] = useState(0);

  const handleClick = () => setCount(c => c + 1);

  return <button onClick={handleClick}>{count}</button>;
}
